/**
 * Presents a searchable list of saved kits. On selection, pre-populates the
 * Roll Setup form with the kit's body, lenses, and filters.
 *
 * Shares [RollSetupViewModel] via the back stack entry so that [onKitSelected]
 * can be called directly without passing complex objects through SavedStateHandle.
 */
@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun KitSelectorScreen(navController: NavHostController) {
    val viewModel: KitSelectorViewModel = viewModel()
    val state by viewModel.state.collectAsStateWithLifecycle()

    // Access the RollSetupViewModel from the back stack entry that is still below
    // this screen. This allows passing the KitWithDetails directly without
    // serialization, since both screens are part of the same nav back stack.
    val rollSetupEntry = navController.getBackStackEntry(RollSetup::class)
    val rollSetupViewModel: RollSetupViewModel = viewModel(rollSetupEntry)

    LaunchedEffect(Unit) {
        viewModel.events.collect { event ->
            when (event) {
                is KitSelectorEvent.KitSelected -> {
                    rollSetupViewModel.onKitSelected(event.kit)
                    navController.popBackStack()
                }
                is KitSelectorEvent.NavigateToNewKit ->
                    navController.navigate(KitDetail(0))
            }
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Select Kit") },
                navigationIcon = {
                    IconButton(onClick = { navController.popBackStack() }) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                    }
                },
            )
        },
        floatingActionButton = {
            FloatingActionButton(onClick = viewModel::onCreateNewKitTapped) {
                Icon(Icons.Default.Add, contentDescription = "New kit")
            }
        },
    ) { innerPadding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding),
        ) {
            OutlinedTextField(
                value = state.searchQuery,
                onValueChange = viewModel::onSearchQueryChanged,
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 8.dp),
                placeholder = { Text("Search kits\u2026") },
                leadingIcon = { Icon(Icons.Default.Search, contentDescription = null) },
                singleLine = true,
            )

            if (state.isLoading) {
                Box(
                    modifier = Modifier.fillMaxSize(),
                    contentAlignment = Alignment.Center,
                ) {
                    CircularProgressIndicator()
                }
            } else if (state.kits.isEmpty()) {
                Box(
                    modifier = Modifier.fillMaxSize(),
                    contentAlignment = Alignment.Center,
                ) {
                    Text(
                        text = if (state.searchQuery.isBlank()) "No kits saved yet"
                               else "No kits match \u201c${state.searchQuery}\u201d",
                        style = MaterialTheme.typography.bodyMedium,
                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                    )
                }
            } else {
                LazyColumn {
                    items(state.kits, key = { it.kit.id }) { kit ->
                        KitSelectorCard(
                            kit = kit,
                            onClick = { viewModel.onKitSelected(kit) },
                            modifier = Modifier.padding(horizontal = 16.dp, vertical = 4.dp),
                        )
                    }
                }
            }
        }
    }
}

// ---------------------------------------------------------------------------
// Kit card
// ---------------------------------------------------------------------------

@Composable
private fun KitSelectorCard(
    kit: KitWithDetails,
    onClick: () -> Unit,
    modifier: Modifier = Modifier,
) {
    Card(
        onClick = onClick,
        modifier = modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(),
        elevation = CardDefaults.cardElevation(defaultElevation = 1.dp),
    ) {
        Column(modifier = Modifier.padding(12.dp)) {
            Text(
                text = kit.kit.name,
                style = MaterialTheme.typography.titleSmall,
                maxLines = 1,
                overflow = TextOverflow.Ellipsis,
            )
            Text(
                text = "${kit.cameraBody.make} ${kit.cameraBody.name}",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant,
            )

            // Lens summary
            if (kit.lenses.isNotEmpty()) {
                val primaryLens = kit.lenses.firstOrNull { it.kitLens.isPrimary }?.lens
                    ?: kit.lenses.first().lens
                val extraCount = kit.lenses.size - 1
                val lensText = buildString {
                    append(primaryLens.name)
                    if (extraCount > 0) append(" +$extraCount more")
                }
                Text(
                    text = lensText,
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant,
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis,
                )
            }

            // Filter summary
            if (kit.filters.isNotEmpty()) {
                Text(
                    text = kit.filters.joinToString(" \u00b7 ") { it.filter.name },
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant,
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis,
                )
            }
        }
    }
}

